type connectionNamespaceJoins[Q dialect.Joinable] struct {
	typ                      string
	Connection               modAs[Q, connectionColumns]
	NamespaceSchemaChunks    modAs[Q, schemaChunkColumns]
	NamespaceSchemaSnapshots modAs[Q, schemaSnapshotColumns]
}

func (j connectionNamespaceJoins[Q]) aliasedAs(alias string) connectionNamespaceJoins[Q] {
	return buildConnectionNamespaceJoins[Q](buildConnectionNamespaceColumns(alias), j.typ)
}

func buildConnectionNamespaceJoins[Q dialect.Joinable](cols connectionNamespaceColumns, typ string) connectionNamespaceJoins[Q] {
	return connectionNamespaceJoins[Q]{
		typ: typ,
		Connection: modAs[Q, connectionColumns]{
			c: Connections.Columns,
			f: func(to connectionColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Connections.Name().As(to.Alias())).On(
						to.ID.EQ(cols.ConnectionID),
					))
				}

				return mods
			},
		},
		NamespaceSchemaChunks: modAs[Q, schemaChunkColumns]{
			c: SchemaChunks.Columns,
			f: func(to schemaChunkColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, SchemaChunks.Name().As(to.Alias())).On(
						to.NamespaceID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		NamespaceSchemaSnapshots: modAs[Q, schemaSnapshotColumns]{
			c: SchemaSnapshots.Columns,
			f: func(to schemaSnapshotColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, SchemaSnapshots.Name().As(to.Alias())).On(
						to.NamespaceID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
	}
}
